import base64,os,subprocess,time,urllib.request,json,sys,datetime
WEB='/home/k/vnt-web'
MP='/mnt/vnt-data/FileServer/VNT_World_AI_Division/MemPalace.md'
TS=datetime.datetime.now().strftime('%Y-%m-%d %H:%M')
os.makedirs(WEB+'/generated',exist_ok=True)
os.makedirs(WEB+'/games',exist_ok=True)
os.makedirs(WEB+'/downloads',exist_ok=True)

# Write portal v3
html=base64.b64decode('')
open(WEB+'/index.html','wb').write(html)
open(WEB+'/media.html','wb').write(html)
print('Portal v3: '+str(len(html))+' bytes written')

# Ensure portal server running
try:
    urllib.request.urlopen('http://127.0.0.1:8888/',timeout=4)
    print('Port 8888: already running')
except:
    print('Restarting portal server...')
    subprocess.run(['fuser','-k','8888/tcp'],capture_output=True)
    time.sleep(1)
    subprocess.Popen(['/usr/bin/python3',WEB+'/portal_server.py'],
        stdout=open('/tmp/portal.log','w'),stderr=subprocess.STDOUT)
    time.sleep(4)
    try:
        urllib.request.urlopen('http://127.0.0.1:8888/',timeout=4)
        print('Port 8888: NOW SERVING')
    except Exception as e:
        print('FAILED:',e)
        print(open('/tmp/portal.log').read()[-300:])

# Install port 8888 as systemd service so it NEVER goes down
svc_path='/etc/systemd/system/vnt-portal.service'
if not os.path.exists(svc_path):
    svc_content='\n'.join([
        '[Unit]','Description=VNT Web Portal','After=network.target','',
        '[Service]','User=k',
        'ExecStart=/usr/bin/python3 /home/k/vnt-web/portal_server.py',
        'Restart=always','RestartSec=5','Environment=PYTHONUNBUFFERED=1','',
        '[Install]','WantedBy=multi-user.target'
    ])
    open('/tmp/vnt-portal.service','w').write(svc_content)
    subprocess.run(['sudo','cp','/tmp/vnt-portal.service',svc_path],capture_output=True)
    subprocess.run(['sudo','systemctl','daemon-reload'],capture_output=True)
    subprocess.run(['sudo','systemctl','enable','vnt-portal'],capture_output=True)
    subprocess.run(['sudo','systemctl','start','vnt-portal'],capture_output=True)
    print('vnt-portal: installed as systemd service (auto-restarts)')
else:
    subprocess.run(['sudo','systemctl','restart','vnt-portal'],capture_output=True)
    print('vnt-portal: restarted via systemd')

# Test proxy
try:
    with urllib.request.urlopen('http://127.0.0.1:8888/api/health',timeout=8) as r:
        d=json.loads(r.read())
        print('Proxy /api/health: '+json.dumps(d)[:60])
except Exception as e:
    print('Proxy test: '+str(e)[:60])

open(MP,'a').write('\n### Portal v3 ['+TS+']\nDeployed: CulturalAssetsGroup.io, Apps tab, Desktop 1+2 tabs, systemd service installed\n')
print('DONE: http://192.168.10.96:8888/')
print('Ctrl+Shift+R to hard refresh')
